2	   AI 洞察 - 天子日课
3	   ============================================ */
4	
5	/* ---- 卡片标题（覆盖全局 .card-title 以适配页面） ---- */
6	.card-title {
7	  display: block;
8	  font-size: var(--text-md);
9	  font-weight: 600;
10	  color: var(--color-text-primary);
11	  margin-bottom: var(--space-md);
12	  letter-spacing: 0.02em;
13	}
14	
15	.card-desc {
16	  display: block;
17	  font-size: var(--text-sm);
18	  color: var(--color-text-muted);
19	  margin-bottom: var(--space-lg);
20	  line-height: 1.6;
21	}
22	
23	/* ---- 洞察正文 ---- */
24	.insight-text {
25	  display: block;
26	  font-size: var(--text-sm);
27	  color: var(--color-text-secondary);
28	  line-height: 1.8;
29	  white-space: pre-wrap;
30	  background: var(--color-surface);
31	  border: 1rpx solid var(--color-border);
32	  border-radius: var(--radius-sm);
33	  padding: var(--space-lg);
34	  margin-top: var(--space-lg);
35	}
36	
37	/* ---- 输入框 ---- */
38	.textarea {
39	  width: 100%;
40	  min-height: 160rpx;
41	  background: var(--color-surface);
42	  border: 1rpx solid var(--color-border);
43	  border-radius: var(--radius-sm);
44	  padding: var(--space-lg);
45	  font-size: var(--text-sm);
46	  color: var(--color-text-primary);
47	  box-sizing: border-box;
48	  line-height: 1.6;
49	  margin-bottom: var(--space-md);
50	}
51	
52	.textarea:focus,
53	.textarea:active {
54	  border-color: var(--color-accent);
55	}
56	
57	/* ---- 操作按钮（覆盖全局 .action-btn） ---- */
58	.card .action-btn {
59	  padding: var(--space-md) var(--space-xl);
60	  border-radius: var(--radius-sm);
61	  background: var(--color-accent);
62	  color: var(--color-text-inverse);
63	  font-size: var(--text-sm);
64	  font-weight: 500;
65	  letter-spacing: 0.02em;
66	  display: inline-block;
67	  transition: opacity 0.2s;
68	}
69	
70	.card .action-btn:active {
71	  opacity: 0.85;
72	}
