1	/* ============================================
2	   个人设置 - 天子日课
3	   ============================================ */
4	
5	/* ---- 保存按钮 ---- */
6	.save-btn {
7	  width: 100%;
8	  height: 88rpx;
9	  border-radius: var(--radius-md);
10	  background: var(--color-accent);
11	  color: var(--color-text-inverse);
12	  font-size: var(--text-md);
13	  font-weight: 500;
14	  display: flex;
15	  align-items: center;
16	  justify-content: center;
17	  margin-top: var(--space-lg);
18	  letter-spacing: 0.04em;
19	  transition: opacity 0.2s;
20	}
21	
22	.save-btn:active {
23	  opacity: 0.85;
24	}
25	
26	/* ---- 需求标签 ---- */
27	.input-tag {
28	  display: inline-block;
29	  background: var(--color-surface);
30	  border: 1rpx solid var(--color-border);
31	  padding: var(--space-xs) var(--space-md);
32	  border-radius: var(--radius-xs);
33	  font-size: var(--text-xs);
34	  color: var(--color-text-secondary);
35	  margin: 0 var(--space-xs) var(--space-sm) 0;
36	}
37	
38	/* ---- 新增需求行 ---- */
39	.input-row {
40	  display: flex;
41	  gap: var(--space-sm);
42	  align-items: center;
43	}
44	
45	.input-row .add-btn {
46	  padding: var(--space-xs) var(--space-lg);
47	  border-radius: var(--radius-sm);
48	  background: var(--color-accent);
49	  color: var(--color-text-inverse);
50	  font-size: var(--text-sm);
51	  font-weight: 500;
52	  white-space: nowrap;
53	  flex-shrink: 0;
54	  transition: opacity 0.2s;
55	}
56	
57	.input-row .add-btn:active {
58	  opacity: 0.85;
59	}
