1	.reminder-card {
2	  margin-bottom: var(--space-lg);
3	}
4	
5	.toggle {
6	  width: 88rpx;
7	  height: 48rpx;
8	  border-radius: 24rpx;
9	  background: var(--color-border);
10	  position: relative;
11	  transition: background 0.25s;
12	}
13	
14	.toggle.active {
15	  background: var(--color-accent);
16	}
17	
18	.toggle-knob {
19	  width: 40rpx;
20	  height: 40rpx;
21	  border-radius: 50%;
22	  background: #fff;
23	  position: absolute;
24	  top: 4rpx;
25	  left: 4rpx;
26	  transition: transform 0.25s;
27	}
28	
29	.toggle.active .toggle-knob {
30	  transform: translateX(40rpx);
31	}
32	
33	.reminder-options {
34	  margin-top: var(--space-lg);
35	  border-top: 1rpx solid var(--color-border);
36	  padding-top: var(--space-lg);
37	}
38	
39	.reminder-time-picker {
40	  display: flex;
41	  justify-content: space-between;
42	  align-items: center;
43	  padding: var(--space-md) 0;
44	}
45	
46	.reminder-label {
47	  font-size: var(--text-sm);
48	  color: var(--color-text-secondary);
49	}
50	
51	.reminder-value {
52	  font-size: var(--text-md);
53	  color: var(--color-accent);
54	  font-weight: 500;
55	  font-feature-settings: "tnum";
56	}
57	
58	.reminder-days {
59	  margin-top: var(--space-md);
60	}
61	
62	.day-buttons {
63	  display: flex;
64	  gap: var(--space-xs);
65	  margin-top: var(--space-sm);
66	}
67	
68	.day-btn {
69	  width: 68rpx;
70	  height: 68rpx;
71	  border-radius: var(--radius-full);
72	  background: var(--color-surface);
73	  border: 1rpx solid var(--color-border);
74	  display: flex;
75	  align-items: center;
76	  justify-content: center;
77	  font-size: var(--text-sm);
78	  color: var(--color-text-muted);
79	  transition: all 0.2s;
80	}
81	
82	.day-btn.selected {
83	  background: var(--color-accent);
84	  border-color: var(--color-accent);
85	  color: #fff;
86	}
87	
88	.day-btn:active {
89	  opacity: 0.7;
90	}
