1	/* ============================================
2	   每日复盘 - 天子日课
3	   ============================================ */
4	
5	/* ---- 复盘卡片 ---- */
6	.review-card {
7	  background: var(--color-card);
8	  border: 1rpx solid var(--color-border);
9	  border-radius: var(--radius-lg);
10	  padding: var(--space-xl);
11	  margin-top: var(--space-xl);
12	}
13	
14	.review-card.center {
15	  text-align: center;
16	}
17	
18	/* ---- 星级评分 ---- */
19	.stars {
20	  display: flex;
21	  gap: var(--space-sm);
22	  justify-content: center;
23	  margin: var(--space-xl) 0;
24	}
25	
26	.star {
27	  font-size: 52rpx;
28	  opacity: 0.2;
29	  filter: grayscale(1);
30	  transition: all 0.2s ease;
31	}
32	
33	.star:active {
34	  transform: scale(1.15);
35	}
36	
37	.star.active {
38	  opacity: 1;
39	  filter: grayscale(0);
40	  transform: scale(1.05);
41	}
42	
43	/* ---- 评分结果 ---- */
44	.review-score {
45	  display: block;
46	  font-size: 80rpx;
47	  margin-bottom: var(--space-sm);
48	  line-height: 1;
49	}
50	
51	.review-summary {
52	  display: block;
53	  font-size: var(--text-md);
54	  color: var(--color-text-secondary);
55	  margin-bottom: var(--space-md);
56	  line-height: 1.6;
57	}
58	
59	/* ---- AI 点评卡片 ---- */
60	.ai-card {
61	  background: linear-gradient(135deg, var(--color-card) 0%, #1e1a15 100%);
62	  border: 1rpx solid var(--color-border);
63	  border-left: 3rpx solid var(--color-accent);
64	  border-radius: var(--radius-lg);
65	  padding: var(--space-xl);
66	  margin-top: var(--space-lg);
67	}
68	
69	.ai-title {
70	  display: block;
71	  font-size: var(--text-md);
72	  font-weight: 600;
73	  color: var(--color-accent-light);
74	  margin-bottom: var(--space-md);
75	  letter-spacing: 0.02em;
76	}
77	
78	.ai-text {
79	  display: block;
80	  font-size: var(--text-sm);
81	  color: var(--color-text-secondary);
82	  line-height: 1.8;
83	  white-space: pre-wrap;
84	}
85	
86	/* ---- 左右双列 ---- */
87	.split-cards {
88	  display: flex;
89	  gap: var(--space-md);
90	  margin-top: var(--space-lg);
91	}
92	
93	.split-card {
94	  flex: 1;
95	  background: var(--color-card);
96	  border: 1rpx solid var(--color-border);
97	  border-radius: var(--radius-md);
98	  padding: var(--space-lg);
99	}
100	
101	.split-label {
102	  display: block;
103	  font-size: 20rpx;
104	  color: var(--color-text-muted);
105	  margin-bottom: var(--space-sm);
106	  letter-spacing: 0.04em;
107	  text-transform: uppercase;
108	}
109	
110	.split-text {
111	  display: block;
112	  font-size: var(--text-sm);
113	  color: var(--color-text-primary);
114	  line-height: 1.6;
115	}
116	
117	/* ---- 提交按钮 ---- */
118	.submit-btn {
119	  width: 100%;
120	  height: 88rpx;
121	  border-radius: var(--radius-md);
122	  background: var(--color-accent);
123	  color: var(--color-text-inverse);
124	  font-size: var(--text-md);
125	  font-weight: 500;
126	  display: flex;
127	  align-items: center;
128	  justify-content: center;
129	  letter-spacing: 0.04em;
130	  transition: opacity 0.2s;
131	}
132	
133	.submit-btn:active {
134	  opacity: 0.85;
135	}
136	
137	/* ---- 多行输入 ---- */
138	.form-textarea {
139	  display: block;
140	  width: 100%;
141	  min-height: 160rpx;
142	  background: var(--color-surface);
143	  border: 1rpx solid var(--color-border);
144	  border-radius: var(--radius-md);
145	  padding: var(--space-md);
146	  font-size: var(--text-sm);
147	  color: var(--color-text-primary);
148	  line-height: 1.6;
149	  resize: none;
150	  box-sizing: border-box;
151	}
152	
153	.form-textarea::placeholder {
154	  color: var(--color-text-muted);
155	}
156	
157	/* ============================================
158	   AI 今日小结卡片
159	   ============================================ */
160	
161	.ai-summary-card {
162	  background: linear-gradient(135deg, #1e1a15 0%, #221e1a 100%);
163	  border: 1rpx solid var(--color-border);
164	  border-left: 6rpx solid var(--color-accent);
165	  border-radius: var(--radius-lg);
166	  padding: var(--space-xl);
167	  margin-top: var(--space-lg);
168	  position: relative;
169	  overflow: hidden;
170	}
171	
172	.ai-summary-card::before {
173	  content: "";
174	  position: absolute;
175	  top: 0;
176	  left: 6rpx;
177	  right: 0;
178	  height: 1rpx;
179	  background: linear-gradient(90deg, var(--color-accent-subtle), transparent);
180	}
181	
182	.ai-summary-header {
183	  display: flex;
184	  align-items: center;
185	  gap: var(--space-sm);
186	  margin-bottom: var(--space-md);
187	}
188	
189	.ai-summary-icon {
190	  font-size: 32rpx;
191	  line-height: 1;
192	}
193	
194	.ai-summary-title {
195	  font-size: var(--text-md);
196	  font-weight: 600;
197	  color: var(--color-accent-light);
198	  letter-spacing: 0.03em;
199	}
200	
201	.ai-summary-text {
202	  display: block;
203	  font-size: var(--text-sm);
204	  color: var(--color-text-secondary);
205	  line-height: 1.8;
206	  white-space: pre-wrap;
207	  padding: var(--space-sm) 0;
208	}
209	
210	.ai-summary-empty-text {
211	  display: block;
212	  font-size: var(--text-sm);
213	  color: var(--color-text-muted);
214	  font-style: italic;
215	  padding: var(--space-sm) 0;
216	}
217	
218	/* ---- 补充感悟输入框 ---- */
219	.ai-summary-supplement {
220	  display: block;
221	  width: 100%;
222	  min-height: 120rpx;
223	  background: var(--color-surface);
224	  border: 1rpx solid var(--color-border);
225	  border-radius: var(--radius-sm);
226	  padding: var(--space-md);
227	  margin-top: var(--space-md);
228	  font-size: var(--text-sm);
229	  color: var(--color-text-primary);
230	  line-height: 1.6;
231	  resize: none;
232	  box-sizing: border-box;
233	}
234	
235	.ai-summary-supplement::placeholder {
236	  color: var(--color-text-muted);
237	  font-style: italic;
238	}
239	
240	/* ---- 降级展示 ---- */
241	.ai-summary-fallback {
242	  opacity: 0.6;
243	}
244	
245	.ai-summary-fallback-text {
246	  display: block;
247	  font-size: var(--text-sm);
248	  color: var(--color-text-muted);
249	  font-style: italic;
250	  padding: var(--space-sm) 0;
251	}
252	
253	/* ---- 骨架屏 ---- */
254	.skeleton-lines {
255	  display: flex;
256	  flex-direction: column;
257	  gap: var(--space-md);
258	  padding: var(--space-sm) 0;
259	}
260	
261	.skeleton-line {
262	  height: 24rpx;
263	  border-radius: 12rpx;
264	  background: linear-gradient(
265	    90deg,
266	    var(--color-border) 25%,
267	    var(--color-border-light) 50%,
268	    var(--color-border) 75%
269	  );
270	  background-size: 200% 100%;
271	  animation: skeleton-shimmer 1.5s ease-in-out infinite;
272	}
273	
274	.skeleton-line.w-80 {
275	  width: 80%;
276	}
277	
278	.skeleton-line.w-60 {
279	  width: 60%;
280	}
281	
282	.skeleton-line.w-70 {
283	  width: 70%;
284	}
285	
286	@keyframes skeleton-shimmer {
287	  0% {
288	    background-position: 200% 0;
289	  }
290	  100% {
291	    background-position: -200% 0;
292	  }
293	}
