2	   习惯管理 - 天子日课
3	   ============================================ */
4	
5	/* ---- 页面头部 ---- */
6	.page-header {
7	  display: flex;
8	  justify-content: space-between;
9	  align-items: flex-start;
10	  margin-bottom: var(--space-xl);
11	}
12	
13	.add-btn {
14	  width: 72rpx;
15	  height: 72rpx;
16	  border-radius: var(--radius-full);
17	  background: var(--color-accent);
18	  color: var(--color-text-inverse);
19	  display: flex;
20	  align-items: center;
21	  justify-content: center;
22	  font-size: 44rpx;
23	  font-weight: 300;
24	  line-height: 1;
25	  transition: opacity 0.2s;
26	}
27	
28	.add-btn:active {
29	  opacity: 0.8;
30	}
31	
32	/* ---- 分类管理入口 ---- */
33	.domain-manager-entry {
34	  display: flex;
35	  align-items: center;
36	  gap: var(--space-md);
37	  padding: var(--space-lg) var(--space-md);
38	  margin-bottom: var(--space-lg);
39	  background: var(--color-card);
40	  border: 1rpx solid var(--color-border);
41	  border-radius: var(--radius-lg);
42	  transition: all 0.2s;
43	}
44	
45	.domain-manager-entry:active {
46	  background: var(--color-card-hover);
47	  border-color: var(--color-border-light);
48	}
49	
50	.domain-manager-entry-bar {
51	  width: 6rpx;
52	  height: 32rpx;
53	  background: var(--color-accent);
54	  border-radius: 3rpx;
55	  flex-shrink: 0;
56	}
57	
58	.domain-manager-entry-text {
59	  flex: 1;
60	  font-size: var(--text-md);
61	  font-weight: 500;
62	  color: var(--color-text-primary);
63	  letter-spacing: 0.02em;
64	}
65	
66	.domain-manager-entry-arrow {
67	  font-size: var(--text-xl);
68	  color: var(--color-text-muted);
69	  flex-shrink: 0;
70	  line-height: 1;
71	}
72	
73	/* ---- 领域标题 ---- */
74	.domain-title {
75	  display: block;
76	  font-size: var(--text-sm);
77	  color: var(--color-text-muted);
78	  margin: var(--space-xl) 0 var(--space-md);
79	  padding-left: var(--space-md);
80	  border-left: 3rpx solid var(--color-accent);
81	}
82	
83	/* ---- 习惯卡片 ---- */
84	.habit-card {
85	  background: var(--color-card);
86	  border: 1rpx solid var(--color-border);
87	  border-radius: var(--radius-md);
88	  padding: var(--space-lg);
89	  margin-bottom: var(--space-sm);
90	  transition: all 0.2s ease;
91	}
92	
93	.habit-card.inactive {
94	  opacity: 0.45;
95	}
96	
97	.habit-info {
98	  margin-bottom: var(--space-md);
99	}
100	
101	.habit-name {
102	  display: block;
103	  font-size: var(--text-md);
104	  font-weight: 500;
105	  color: var(--color-text-primary);
106	  letter-spacing: 0.02em;
107	}
108	
109	.habit-desc {
110	  display: block;
111	  font-size: var(--text-xs);
112	  color: var(--color-text-muted);
113	  margin-top: var(--space-xs);
114	}
115	
116	.habit-meta {
117	  display: block;
118	  font-size: var(--text-xs);
119	  color: var(--color-text-muted);
120	  margin-top: var(--space-sm);
121	  font-feature-settings: "tnum";
122	}
123	
124	/* ---- 卡片操作按钮 ---- */
125	.habit-actions {
126	  display: flex;
127	  gap: var(--space-sm);
128	}
129	
130	.habit-actions .action-btn {
131	  padding: var(--space-xs) var(--space-md);
132	  border-radius: var(--radius-xs);
133	  font-size: var(--text-xs);
134	  font-weight: 500;
135	  background: var(--color-surface);
136	  color: var(--color-text-secondary);
137	  border: 1rpx solid var(--color-border);
138	  transition: all 0.2s;
139	}
140	
141	.habit-actions .action-btn:active {
142	  background: var(--color-border);
143	}
144	
145	.habit-actions .action-btn.danger {
146	  background: var(--color-danger-subtle);
147	  color: var(--color-danger);
148	  border-color: transparent;
149	}
150	
151	.habit-actions .action-btn.danger:active {
152	  opacity: 0.8;
153	}
154	
155	.habit-actions .action-btn.disabled {
156	  opacity: 0.4;
157	}
158	
159	/* ============================================
160	   分类管理 - 重设计
161	   ============================================ */
162	
163	/* ---- 弹窗顶饰 ---- */
164	.domain-manager-accent {
165	  width: 48rpx;
166	  height: 4rpx;
167	  background: var(--color-accent);
168	  border-radius: 2rpx;
169	  margin: 0 auto var(--space-xl);
170	  opacity: 0.6;
171	}
172	
173	/* ---- 弹窗头部 ---- */
174	.modal-header-row {
175	  display: flex;
176	  justify-content: space-between;
177	  align-items: center;
178	  margin-bottom: var(--space-xl);
179	}
180	
181	.modal-header-row .modal-title {
182	  margin-bottom: 0;
183	}
184	
185	.modal-add-btn {
186	  display: flex;
187	  align-items: center;
188	  gap: var(--space-xs);
189	  font-size: var(--text-sm);
190	  font-weight: 500;
191	  color: var(--color-accent);
192	  padding: var(--space-xs) var(--space-md);
193	  border: 1rpx solid var(--color-accent-subtle);
194	  border-radius: var(--radius-sm);
195	  background: var(--color-accent-subtle);
196	}
197	
198	/* ---- 分类列表项（卡片式） ---- */
199	.domain-item {
200	  display: flex;
201	  align-items: center;
202	  gap: var(--space-md);
203	  padding: var(--space-lg) var(--space-md);
204	  margin-bottom: var(--space-sm);
205	  background: var(--color-surface);
206	  border: 1rpx solid var(--color-border);
207	  border-radius: var(--radius-md);
208	  transition: all 0.2s;
209	}
210	
211	.domain-item:active {
212	  background: var(--color-card-hover);
213	}
214	
215	.domain-item-bar {
216	  width: 6rpx;
